            // Save current cost
            oldCost := dispatch.Assigns[i].Cost

            // Trial insert
            if dispatch.Assigns[i].AddShip(shipID, ori, des) {
                dispatch.Assigns[i].GenRoute()
                if dispatch.Assigns[i].Cost >= 0 {
                    costDelta := dispatch.Assigns[i].Cost - oldCost
                    if costDelta < bestTrial.costDelta {
                        bestTrial.idx = i
                        bestTrial.costDelta = costDelta
                        bestTrial.ok = true
                    }
                }

                // Rollback
                dispatch.Assigns[i].RemoveShip(shipID)
                dispatch.Assigns[i].GenRoute()
            }
        }

        // Also try potential new empty assign (if within bounds)
        if nextAssignIdx < MAXASSIGNS {
