Evaluate insertion cost using a normalized composite score balancing distance, time window slack, and load efficiency, committing to the best feasible insertion across existing assigns and new assign fallback.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	validAssigns := make([]int, 0, dispatch.AssignsLen)
	for i := 0; i < dispatch.AssignsLen; i++ {
		if dispatch.Assigns[i].Cost >= 0 {
			validAssigns = append(validAssigns, i)
		}
	}

	for shipIdx := 0; shipIdx < orderCount; shipIdx++ {
		id := total_ship + shipIdx
		ori := oris[shipIdx]
		des := dess[shipIdx]

		type candidate struct {
			idx       int
			isNew     bool
			score     float64
			deltaCost float64
		}
		var bestCandidate *candidate

		evaluateAssign := func(idx int, isNew bool) {
			var savedCost float64
			var hadCost bool
			if !isNew && idx < dispatch.AssignsLen && dispatch.Assigns[idx].Cost >= 0 {
				savedCost = dispatch.Assigns[idx].Cost
				hadCost = true
			}
			ok := dispatch.Assigns[idx].AddShip(id, ori, des)
			if !ok {
				return
			}
			dispatch.Assigns[idx].GenRoute()
			newCost := dispatch.Assigns[idx].Cost
			if newCost < 0 {
				dispatch.Assigns[idx].RemoveShip(id)
				return
			}
			delta := newCost
			if hadCost {
				delta = newCost - savedCost
			}
			dispatch.Assigns[idx].RemoveShip(id)
			if hadCost {
				dispatch.Assigns[idx].Cost = savedCost
			}

			baseDist := cal_dis(ori, des)
			timeSlack := 0.0
			loadFactor := 1.0
			if !isNew && idx < dispatch.AssignsLen {
				if dispatch.Assigns[idx].StationCurrent.TimeEnd > 0 && ori.TimeEnd > 0 {
					wait := float64(ori.TimeStart) - float64(dispatch.Assigns[idx].StationCurrent.TimeEnd)
					if wait < 0 {
						wait = 0
					}
					timeSlack = wait / 1000.0
				}
				if ori.Load > 0 && des.Load > 0 {
					loadDiff := float64(ori.Load-des.Load) / 10.0
					if loadDiff < 0 {
						loadDiff = -loadDiff
					}
					loadFactor = 1.0 + loadDiff/50.0
				}
			}
			normDist := baseDist / 1000.0
			if normDist < 0.01 {
				normDist = 0.01
			}
			score := delta/normDist*0.5 + timeSlack*0.3 + (delta*loadFactor)/normDist*0.2

			if bestCandidate == nil || score < bestCandidate.score {
				bestCandidate = &candidate{idx: idx, isNew: isNew, score: score, deltaCost: delta}
			}
		}

		for _, idx := range validAssigns {
			if idx < 0 || idx >= MAXASSIGNS {
				continue
			}
			evaluateAssign(idx, false)
		}
		if dispatch.AssignsLen < MAXASSIGNS {
			evaluateAssign(dispatch.AssignsLen, true)
		}

		inserted := false
		if bestCandidate != nil {
			tidx := bestCandidate.idx
			if bestCandidate.isNew && tidx >= dispatch.AssignsLen {
				if dispatch.Assigns[tidx].AddShip(id, ori, des) {
					dispatch.Assigns[tidx].GenRoute()
					dispatch.AssignsLen++
					inserted = true
				}
			} else if tidx >= 0 && tidx < MAXASSIGNS {
				if dispatch.Assigns[tidx].AddShip(id, ori, des) {
					dispatch.Assigns[tidx].GenRoute()
					inserted = true
				}
			}
		}
		if !inserted {
			if dispatch.AssignsLen < MAXASSIGNS {
				tidx := dispatch.AssignsLen
				if dispatch.Assigns[tidx].AddShip(id, ori, des) {
					dispatch.Assigns[tidx].GenRoute()
					dispatch.AssignsLen++
					inserted = true
				}
			}
		}
		if !inserted && dispatch.AssignsLen > 0 {
			if dispatch.Assigns[0].AddShip(id, ori, des) {
				dispatch.Assigns[0].GenRoute()
				inserted = true
			}
		}

		if inserted {
			validAssigns = validAssigns[:0]
			for i := 0; i < dispatch.AssignsLen; i++ {
				if dispatch.Assigns[i].Cost >= 0 {
					validAssigns = append(validAssigns, i)
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

